207 +    private boolean hasPermission(ClientModel client, String scope) {
208 +        if (!root.isAdminSameRealm()) {
209 +            return false;
210 +        }
211 +        ResourceServer server = root.realmResourceServer();
212 +        if (server == null) return false;
213 +
214 +        Resource resource =  resourceStore.findByName(server, client.getId(), server.getId());
215 +        if (resource == null) {
216 +            // check if there is permission for "all-clients". If so, load its resource and proceed with evaluation
217 +            resource = AdminPermissionsSchema.SCHEMA.getResourceTypeResource(session, server, AdminPermissionsSchema.CLIENTS_RESOURCE_TYPE);
218 +
219 +            if (authz.getStoreFactory().getPolicyStore().findByResource(server, resource).isEmpty()) {
220 +                return false;
221 +            }
222 +        }
223 +
224 +        Collection<Permission> permissions = root.evaluatePermission(new ResourcePermission(resource, resource.getScopes(), server), server);
225 +        List<String> expectedScopes = Arrays.asList(scope);
226 +        for (Permission permission : permissions) {
227 +            for (String s : permission.getScopes()) {
228 +                if (expectedScopes.contains(s)) {
229 +                    return true;
230 +                }
231 +            }
